import java.util.HashMap;
import java.util.ArrayList;

class WordDistance {
    HashMap<String, ArrayList<Integer>> wordIndexes;

    public WordDistance(String[] wordsDict) {
        wordIndexes = new HashMap<>();
        for (int i = 0; i < wordsDict.length; ++i) {
            if (!wordIndexes.containsKey(wordsDict[i])) {
                wordIndexes.put(wordsDict[i], new ArrayList<>());
            }
            wordIndexes.get(wordsDict[i]).add(i);
        }
    }

    public int shortest(String word1, String word2) {
        ArrayList<Integer> indexes1 = wordIndexes.get(word1);
        ArrayList<Integer> indexes2 = wordIndexes.get(word2);
        int i = 0, j = 0, min_dist = Integer.MAX_VALUE;

        while (i < indexes1.size() && j < indexes2.size()) {
            min_dist = Math.min(min_dist, Math.abs(indexes1.get(i) - indexes2.get(j)));
            if (indexes1.get(i) < indexes2.get(j)) {
                ++i;
            } else {
                ++j;
            }
        }
        return min_dist;
    }
}
